INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6006, 0.3, "あたしも教官の仕事を\n頑張れば、あいつに\n喜んでもらえたり\nするのかな…", 0, 1, 6, 0, 129811, 0, 8, 11);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6007, "", "", "", "", 6, "", 0, "", "", 91);
