INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6014, "", "drama_talk_surprise_in_shy", "", "drama_talk_surprise_loop_shy", 6, 0.2, 129811, 1, 0, 3);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6015, "", "vo_minigame_1013_top_talk_6_002", "", 0, 6, "", "vo_minigame_1013", "", 0, 21);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6016, 0.3, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 0, 1, 6, 0, 129811, 0, 9, 11);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (6017, "", "", "", "", 6, "", 0, "", "", 91);
