INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (7011, 0, "エリコ班の急成長は\n騎士団の中でも話題に\nなってたからな\nホントすげえ奴等だよ", 0, 1, 7, 0, 129811, 0, 6, 11);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (7012, "", "", "", "", 7, "", 0, "", "", 91);
