INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (7015, "", "vo_minigame_1013_top_talk_7_002", "", 0, 7, "", "vo_minigame_1013", "", 0, 21);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (7016, 0.5, "彼らが私に逆らわずに\n努力したからこそ、\n得たものもありますし\n…感謝しておきますわ", 0, 1, 7, 0, 129911, 0, 6, 11);
